// SecurityManager.js
import CryptoJS from 'crypto-js';
import { PAYMENT_CONFIG } from './paymentConfig';

class SecurityManager {
  constructor() {
    this.encryptionKey = PAYMENT_CONFIG.ENCRYPTION_KEY;
  }

  encryptData(data) {
    try {
      const encrypted = CryptoJS.AES.encrypt(
        JSON.stringify(data),
        this.encryptionKey
      ).toString();
      return encrypted;
    } catch (error) {
      console.error('Encryption error:', error);
      throw new Error('Failed to encrypt data');
    }
  }

  decryptData(encryptedData) {
    try {
      const bytes = CryptoJS.AES.decrypt(encryptedData, this.encryptionKey);
      const decrypted = JSON.parse(bytes.toString(CryptoJS.enc.Utf8));
      return decrypted;
    } catch (error) {
      console.error('Decryption error:', error);
      throw new Error('Failed to decrypt data');
    }
  }

  sanitizeCardNumber(cardNumber) {
    return cardNumber.replace(/\s/g, '').replace(/[^0-9]/g, '');
  }

  validateCardNumber(cardNumber) {
    const sanitized = this.sanitizeCardNumber(cardNumber);
    
    if (sanitized.length < 13 || sanitized.length > 19) {
      return false;
    }

    let sum = 0;
    let isEven = false;

    for (let i = sanitized.length - 1; i >= 0; i--) {
      let digit = parseInt(sanitized[i], 10);

      if (isEven) {
        digit *= 2;
        if (digit > 9) {
          digit -= 9;
        }
      }

      sum += digit;
      isEven = !isEven;
    }

    return sum % 10 === 0;
  }

  validateCVV(cvv, cardType = 'visa') {
    const cvvLength = cardType === 'amex' ? 4 : 3;
    return /^\d+$/.test(cvv) && cvv.length === cvvLength;
  }

  validateExpiryDate(month, year) {
    const currentDate = new Date();
    const currentMonth = currentDate.getMonth() + 1;
    const currentYear = currentDate.getFullYear();

    const expMonth = parseInt(month, 10);
    const expYear = parseInt(year, 10);

    if (expMonth < 1 || expMonth > 12) {
      return false;
    }

    const fullYear = expYear < 100 ? 2000 + expYear : expYear;

    if (fullYear < currentYear) {
      return false;
    }

    if (fullYear === currentYear && expMonth < currentMonth) {
      return false;
    }

    return true;
  }

  maskCardNumber(cardNumber) {
    const sanitized = this.sanitizeCardNumber(cardNumber);
    const lastFour = sanitized.slice(-4);
    return `**** **** **** ${lastFour}`;
  }

  generateTransactionId() {
    const timestamp = Date.now();
    const random = Math.random().toString(36).substring(2, 15);
    return `TXN-${timestamp}-${random}`.toUpperCase();
  }

  hashData(data) {
    return CryptoJS.SHA256(JSON.stringify(data)).toString();
  }

  verifyIntegrity(data, hash) {
    return this.hashData(data) === hash;
  }
}

export default new SecurityManager();

// PaymentValidator.js
import SecurityManager from './SecurityManager';

export class PaymentValidator {
  static validateCardPayment(paymentData) {
    const errors = {};

    if (!paymentData.cardNumber || !SecurityManager.validateCardNumber(paymentData.cardNumber)) {
      errors.cardNumber = 'Invalid card number';
    }

    if (!paymentData.cvv || !SecurityManager.validateCVV(paymentData.cvv)) {
      errors.cvv = 'Invalid CVV';
    }

    if (!paymentData.expiryMonth || !paymentData.expiryYear ||
        !SecurityManager.validateExpiryDate(paymentData.expiryMonth, paymentData.expiryYear)) {
      errors.expiry = 'Invalid expiry date';
    }

    if (!paymentData.cardholderName || paymentData.cardholderName.trim().length < 3) {
      errors.cardholderName = 'Invalid cardholder name';
    }

    if (!paymentData.amount || paymentData.amount <= 0) {
      errors.amount = 'Invalid amount';
    }

    return {
      isValid: Object.keys(errors).length === 0,
      errors,
    };
  }

  static validateBillingAddress(address) {
    const errors = {};

    if (!address.line1 || address.line1.trim().length < 5) {
      errors.line1 = 'Invalid address';
    }

    if (!address.city || address.city.trim().length < 2) {
      errors.city = 'Invalid city';
    }

    if (!address.postalCode || address.postalCode.trim().length < 3) {
      errors.postalCode = 'Invalid postal code';
    }

    if (!address.country || address.country.trim().length !== 2) {
      errors.country = 'Invalid country code';
    }

    return {
      isValid: Object.keys(errors).length === 0,
      errors,
    };
  }

  static validateAmount(amount, currency) {
    if (typeof amount !== 'number' || amount <= 0) {
      return { isValid: false, error: 'Invalid amount' };
    }

    if (!currency || currency.length !== 3) {
      return { isValid: false, error: 'Invalid currency' };
    }

    const maxAmount = 10000;
    if (amount > maxAmount) {
      return { isValid: false, error: `Amount exceeds maximum of ${maxAmount}` };
    }

    return { isValid: true };
  }
}

