import { PAYMENT_CONFIG } from './paymentConfig';
import SecurityManager from './SecurityManager';

export class StripePaymentProvider {
  constructor() {
    this.publishableKey = PAYMENT_CONFIG.STRIPE_PUBLISHABLE_KEY;
  }

  async createPaymentIntent(amount, currency = 'usd') {
    try {
      const response = await fetch('https://api.stripe.com/v1/payment_intents', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.publishableKey}`,
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `amount=${Math.round(amount * 100)}&currency=${currency}`,
      });

      const data = await response.json();
      
      if (!response.ok) {
        throw new Error(data.error?.message || 'Failed to create payment intent');
      }

      return {
        success: true,
        clientSecret: data.client_secret,
        paymentIntentId: data.id,
      };
    } catch (error) {
      console.error('Stripe payment intent error:', error);
      return {
        success: false,
        error: error.message,
      };
    }
  }

  async confirmCardPayment(clientSecret, paymentMethod) {
    try {
      const encryptedCard = SecurityManager.encryptData({
        number: paymentMethod.cardNumber,
        exp_month: paymentMethod.expiryMonth,
        exp_year: paymentMethod.expiryYear,
        cvc: paymentMethod.cvv,
      });

      const response = await fetch('YOUR_BACKEND_URL/confirm-payment', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          clientSecret,
          encryptedCard,
          billingDetails: {
            name: paymentMethod.cardholderName,
            address: paymentMethod.billingAddress,
          },
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Payment confirmation failed');
      }

      return {
        success: true,
        paymentIntent: data.paymentIntent,
      };
    } catch (error) {
      console.error('Card payment confirmation error:', error);
      return {
        success: false,
        error: error.message,
      };
    }
  }

  async processRefund(paymentIntentId, amount) {
    try {
      const response = await fetch('YOUR_BACKEND_URL/create-refund', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          paymentIntentId,
          amount: amount ? Math.round(amount * 100) : undefined,
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || 'Refund failed');
      }

      return {
        success: true,
        refund: data.refund,
      };
    } catch (error) {
      console.error('Refund error:', error);
      return {
        success: false,
        error: error.message,
      };
    }
  }
}

