// PaymentStorage.js
import AsyncStorage from '@react-native-async-storage/async-storage';
import SecurityManager from './SecurityManager';

export class PaymentStorage {
  static KEYS = {
    PAYMENT_METHODS: 'payment_methods',
    TRANSACTIONS: 'transactions',
    WALLET_BALANCE: 'wallet_balance',
  };

  static async savePaymentMethod(paymentMethod) {
    try {
      const methods = await this.getPaymentMethods();
      
      const encryptedMethod = {
        id: SecurityManager.generateTransactionId(),
        type: paymentMethod.type,
        last4: paymentMethod.cardNumber.slice(-4),
        brand: this.detectCardBrand(paymentMethod.cardNumber),
        expiryMonth: paymentMethod.expiryMonth,
        expiryYear: paymentMethod.expiryYear,
        cardholderName: paymentMethod.cardholderName,
        isDefault: methods.length === 0,
        createdAt: new Date().toISOString(),
      };

      methods.push(encryptedMethod);

      const encrypted = SecurityManager.encryptData(methods);
      await AsyncStorage.setItem(this.KEYS.PAYMENT_METHODS, encrypted);

      return { success: true, paymentMethod: encryptedMethod };
    } catch (error) {
      console.error('Save payment method error:', error);
      return { success: false, error: error.message };
    }
  }

  static async getPaymentMethods() {
    try {
      const encrypted = await AsyncStorage.getItem(this.KEYS.PAYMENT_METHODS);
      
      if (!encrypted) {
        return [];
      }

      return SecurityManager.decryptData(encrypted);
    } catch (error) {
      console.error('Get payment methods error:', error);
      return [];
    }
  }

  static async removePaymentMethod(methodId) {
    try {
      const methods = await this.getPaymentMethods();
      const filtered = methods.filter(method => method.id !== methodId);

      const encrypted = SecurityManager.encryptData(filtered);
      await AsyncStorage.setItem(this.KEYS.PAYMENT_METHODS, encrypted);

      return { success: true };
    } catch (error) {
      console.error('Remove payment method error:', error);
      return { success: false, error: error.message };
    }
  }

  static async setDefaultPaymentMethod(methodId) {
    try {
      const methods = await this.getPaymentMethods();
      
      methods.forEach(method => {
        method.isDefault = method.id === methodId;
      });

      const encrypted = SecurityManager.encryptData(methods);
      await AsyncStorage.setItem(this.KEYS.PAYMENT_METHODS, encrypted);

      return { success: true };
    } catch (error) {
      console.error('Set default payment method error:', error);
      return { success: false, error: error.message };
    }
  }

  static async saveTransaction(transaction) {
    try {
      const transactions = await this.getTransactions();
      
      const encryptedTransaction = SecurityManager.encryptData({
        ...transaction,
        timestamp: new Date().toISOString(),
      });

      transactions.unshift({
        id: transaction.id,
        encrypted: encryptedTransaction,
      });

      if (transactions.length > 100) {
        transactions.splice(100);
      }

      await AsyncStorage.setItem(this.KEYS.TRANSACTIONS, JSON.stringify(transactions));

      return { success: true };
    } catch (error) {
      console.error('Save transaction error:', error);
      return { success: false, error: error.message };
    }
  }

  static async getTransactions() {
    try {
      const data = await AsyncStorage.getItem(this.KEYS.TRANSACTIONS);
      
      if (!data) {
        return [];
      }

      const transactions = JSON.parse(data);
      
      return transactions.map(item => ({
        id: item.id,
        ...SecurityManager.decryptData(item.encrypted),
      }));
    } catch (error) {
      console.error('Get transactions error:', error);
      return [];
    }
  }

  static async getWalletBalance() {
    try {
      const encrypted = await AsyncStorage.getItem(this.KEYS.WALLET_BALANCE);
      
      if (!encrypted) {
        return { balance: 0, currency: 'USD' };
      }

      return SecurityManager.decryptData(encrypted);
    } catch (error) {
      console.error('Get wallet balance error:', error);
      return { balance: 0, currency: 'USD' };
    }
  }

  static async updateWalletBalance(amount, currency = 'USD') {
    try {
      const current = await this.getWalletBalance();
      const newBalance = {
        balance: current.balance + amount,
        currency,
        lastUpdated: new Date().toISOString(),
      };

      const encrypted = SecurityManager.encryptData(newBalance);
      await AsyncStorage.setItem(this.KEYS.WALLET_BALANCE, encrypted);

      return { success: true, balance: newBalance };
    } catch (error) {
      console.error('Update wallet balance error:', error);
      return { success: false, error: error.message };
    }
  }

  static detectCardBrand(cardNumber) {
    const sanitized = SecurityManager.sanitizeCardNumber(cardNumber);
    
    if (/^4/.test(sanitized)) return 'visa';
    if (/^5[1-5]/.test(sanitized)) return 'mastercard';
    if (/^3[47]/.test(sanitized)) return 'amex';
    if (/^6(?:011|5)/.test(sanitized)) return 'discover';
    
    return 'unknown';
  }

  static async clearAllData() {
    try {
      await AsyncStorage.multiRemove(Object.values(this.KEYS));
      return { success: true };
    } catch (error) {
      console.error('Clear all data error:', error);
      return { success: false, error: error.message };
    }
  }
}

