import { StripePaymentProvider } from './StripePaymentProvider';
import { InAppPurchaseManager } from './InAppPurchaseManager';
import { DigitalWalletManager } from './DigitalWalletManager';
import { PaymentStorage } from './PaymentStorage';
import { PaymentValidator } from './PaymentValidator';
import SecurityManager from './SecurityManager';
import { PAYMENT_METHODS } from './paymentConfig';

export class PaymentManager {
  constructor() {
    this.stripeProvider = new StripePaymentProvider();
    this.iapManager = new InAppPurchaseManager();
    this.walletManager = new DigitalWalletManager();
    this.listeners = [];
  }

  async initialize() {
    try {
      await this.iapManager.initialize();
      
      this.iapManager.addListener('purchase_completed', (transaction) => {
        this.notifyListeners('payment_success', {
          method: 'in_app_purchase',
          transaction,
        });
      });

      return { success: true };
    } catch (error) {
      console.error('Payment manager initialization error:', error);
      return { success: false, error: error.message };
    }
  }

  async processCardPayment(paymentData) {
    try {
      const validation = PaymentValidator.validateCardPayment(paymentData);
      
      if (!validation.isValid) {
        return {
          success: false,
          errors: validation.errors,
        };
      }

      const transactionId = SecurityManager.generateTransactionId();

      const intent = await this.stripeProvider.createPaymentIntent(
        paymentData.amount,
        paymentData.currency || 'usd'
      );

      if (!intent.success) {
        throw new Error(intent.error);
      }

      const confirmation = await this.stripeProvider.confirmCardPayment(
        intent.clientSecret,
        paymentData
      );

      if (!confirmation.success) {
        throw new Error(confirmation.error);
      }

      const transaction = {
        id: transactionId,
        method: PAYMENT_METHODS.CREDIT_CARD,
        amount: paymentData.amount,
        currency: paymentData.currency || 'usd',
        status: 'completed',
        paymentIntentId: intent.paymentIntentId,
        last4: paymentData.cardNumber.slice(-4),
      };

      await PaymentStorage.saveTransaction(transaction);

      if (paymentData.saveCard) {
        await PaymentStorage.savePaymentMethod(paymentData);
      }

      this.notifyListeners('payment_success', transaction);

      return {
        success: true,
        transaction,
      };
    } catch (error) {
      console.error('Card payment error:', error);
      
      this.notifyListeners('payment_failed', {
        error: error.message,
      });

      return {
        success: false,
        error: error.message,
      };
    }
  }

  async processApplePayPayment(amount, currency = 'USD') {
    try {
      const result = await this.walletManager.processApplePayPayment(amount, currency);

      if (!result.success) {
        throw new Error(result.error);
      }

      const transaction = {
        id: SecurityManager.generateTransactionId(),
        method: PAYMENT_METHODS.APPLE_PAY,
        amount,
        currency,
        status: 'completed',
        token: result.payment.token,
      };

      await PaymentStorage.saveTransaction(transaction);

      this.notifyListeners('payment_success', transaction);

      return {
        success: true,
        transaction,
      };
    } catch (error) {
      console.error('Apple Pay error:', error);
      
      this.notifyListeners('payment_failed', {
        error: error.message,
      });

      return {
        success: false,
        error: error.message,
      };
    }
  }

  async processGooglePayPayment(amount, currency = 'USD') {
    try {
      const result = await this.walletManager.processGooglePayPayment(amount, currency);

      if (!result.success) {
        throw new Error(result.error);
      }

      const transaction = {
        id: SecurityManager.generateTransactionId(),
        method: PAYMENT_METHODS.GOOGLE_PAY,
        amount,
        currency,
        status: 'completed',
        token: result.payment.token,
      };

      await PaymentStorage.saveTransaction(transaction);

      this.notifyListeners('payment_success', transaction);

      return {
        success: true,
        transaction,
      };
    } catch (error) {
      console.error('Google Pay error:', error);
      
      this.notifyListeners('payment_failed', {
        error: error.message,
      });

      return {
        success: false,
        error: error.message,
      };
    }
  }

  async purchaseInAppProduct(productId) {
    try {
      const result = await this.iapManager.purchaseProduct(productId);

      if (!result.success) {
        throw new Error(result.error);
      }

      const transaction = {
        id: result.transaction.transactionId,
        method: 'in_app_purchase',
        productId,
        status: 'completed',
        receipt: result.transaction.transactionReceipt,
      };

      await PaymentStorage.saveTransaction(transaction);

      return {
        success: true,
        transaction,
      };
    } catch (error) {
      console.error('In-app purchase error:', error);
      return {
        success: false,
        error: error.message,
      };
    }
  }

  async restorePurchases() {
    return await this.iapManager.restorePurchases();
  }

  async refundTransaction(transactionId, amount) {
    try {
      const transactions = await PaymentStorage.getTransactions();
      const transaction = transactions.find(t => t.id === transactionId);

      if (!transaction) {
        throw new Error('Transaction not found');
      }

      if (transaction.method !== PAYMENT_METHODS.CREDIT_CARD) {
        throw new Error('Only card payments can be refunded');
      }

      const result = await this.stripeProvider.processRefund(
        transaction.paymentIntentId,
        amount
      );

      if (!result.success) {
        throw new Error(result.error);
      }

      const refundTransaction = {
        id: SecurityManager.generateTransactionId(),
        method: 'refund',
        amount: amount || transaction.amount,
        currency: transaction.currency,
        status: 'completed',
        originalTransactionId: transactionId,
      };

      await PaymentStorage.saveTransaction(refundTransaction);

      this.notifyListeners('refund_success', refundTransaction);

      return {
        success: true,
        refund: refundTransaction,
      };
    } catch (error) {
      console.error('Refund error:', error);
      return {
        success: false,
        error: error.message,
      };
    }
  }

  async getPaymentMethods() {
    return await PaymentStorage.getPaymentMethods();
  }

  async getTransactionHistory() {
    return await PaymentStorage.getTransactions();
  }

  async getWalletBalance() {
    return await PaymentStorage.getWalletBalance();
  }

  async addFundsToWallet(amount, paymentMethod) {
    try {
      let result;

      if (paymentMethod.type === PAYMENT_METHODS.CREDIT_CARD) {
        result = await this.processCardPayment({
          ...paymentMethod,
          amount,
        });
      } else if (paymentMethod.type === PAYMENT_METHODS.APPLE_PAY) {
        result = await this.processApplePayPayment(amount);
      } else if (paymentMethod.type === PAYMENT_METHODS.GOOGLE_PAY) {
        result = await this.processGooglePayPayment(amount);
      }

      if (!result.success) {
        throw new Error(result.error);
      }

      await PaymentStorage.updateWalletBalance(amount);

      return {
        success: true,
        balance: await PaymentStorage.getWalletBalance(),
      };
    } catch (error) {
      console.error('Add funds error:', error);
      return {
        success: false,
        error: error.message,
      };
    }
  }

  async withdrawFromWallet(amount, destination) {
    try {
      const balance = await PaymentStorage.getWalletBalance();

      if (balance.balance < amount) {
        throw new Error('Insufficient funds');
      }

      await PaymentStorage.updateWalletBalance(-amount);

      const transaction = {
        id: SecurityManager.generateTransactionId(),
        method: 'withdrawal',
        amount,
        currency: balance.currency,
        status: 'completed',
        destination,
      };

      await PaymentStorage.saveTransaction(transaction);

      return {
        success: true,
        transaction,
        balance: await PaymentStorage.getWalletBalance(),
      };
    } catch (error) {
      console.error('Withdraw error:', error);
      return {
        success: false,
        error: error.message,
      };
    }
  }

  addListener(event, callback) {
    this.listeners.push({ event, callback });
  }

  removeListener(callback) {
    this.listeners = this.listeners.filter(listener => listener.callback !== callback);
  }

  notifyListeners(event, data) {
    this.listeners
      .filter(listener => listener.event === event)
      .forEach(listener => listener.callback(data));
  }
}

export default new PaymentManager();

// Example usage component - PaymentScreen.js
import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  ScrollView,
  Alert,
  ActivityIndicator,
} from 'react-native';
import PaymentManager from './PaymentManager';
import { PAYMENT_METHODS } from './paymentConfig';

export const PaymentScreen = () => {
  const [loading, setLoading] = useState(false);
  const [cardNumber, setCardNumber] = useState('');
  const [expiryMonth, setExpiryMonth] = useState('');
  const [expiryYear, setExpiryYear] = useState('');
  const [cvv, setCvv] = useState('');
  const [cardholderName, setCardholderName] = useState('');
  const [amount, setAmount] = useState('');
  const [paymentMethods, setPaymentMethods] = useState([]);
  const [transactions, setTransactions] = useState([]);

  useEffect(() => {
    initializePayments();
  }, []);

  const initializePayments = async () => {
    await PaymentManager.initialize();
    loadPaymentMethods();
    loadTransactions();

    PaymentManager.addListener('payment_success', (transaction) => {
      Alert.alert('Success', 'Payment processed successfully');
      loadTransactions();
    });

    PaymentManager.addListener('payment_failed', (data) => {
      Alert.alert('Error', data.error);
    });
  };

  const loadPaymentMethods = async () => {
    const methods = await PaymentManager.getPaymentMethods();
    setPaymentMethods(methods);
  };

  const loadTransactions = async () => {
    const history = await PaymentManager.getTransactionHistory();
    setTransactions(history);
  };

  const handleCardPayment = async () => {
    setLoading(true);

    const result = await PaymentManager.processCardPayment({
      cardNumber,
      expiryMonth,
      expiryYear,
      cvv,
      cardholderName,
      amount: parseFloat(amount),
      currency: 'usd',
      saveCard: true,
      billingAddress: {
        line1: '123 Main St',
        city: 'San Francisco',
        postalCode: '94111',
        country: 'US',
      },
    });

    setLoading(false);

    if (result.success) {
      setCardNumber('');
      setExpiryMonth('');
      setExpiryYear('');
      setCvv('');
      setCardholderName('');
      setAmount('');
    }
  };

  const handleApplePay = async () => {
    setLoading(true);
    await PaymentManager.processApplePayPayment(parseFloat(amount));
    setLoading(false);
  };

  const handleGooglePay = async () => {
    setLoading(true);
    await PaymentManager.processGooglePayPayment(parseFloat(amount));
    setLoading(false);
  };

  return (
    <ScrollView style={styles.container}>
      <Text style={styles.title}>Payment</Text>

      <View style={styles.section}>
        <Text style={styles.label}>Amount</Text>
        <TextInput
          style={styles.input}
          placeholder="0.00"
          keyboardType="decimal-pad"
          value={amount}
          onChangeText={setAmount}
        />
      </View>

      <View style={styles.section}>
        <Text style={styles.label}>Card Number</Text>
        <TextInput
          style={styles.input}
          placeholder="1234 5678 9012 3456"
          keyboardType="number-pad"
          value={cardNumber}
          onChangeText={setCardNumber}
          maxLength={19}
        />
      </View>

      <View style={styles.row}>
        <View style={styles.halfSection}>
          <Text style={styles.label}>Expiry Month</Text>
          <TextInput
            style={styles.input}
            placeholder="MM"
            keyboardType="number-pad"
            value={expiryMonth}
            onChangeText={setExpiryMonth}
            maxLength={2}
          />
        </View>

        <View style={styles.halfSection}>
          <Text style={styles.label}>Expiry Year</Text>
          <TextInput
            style={styles.input}
            placeholder="YY"
            keyboardType="number-pad"
            value={expiryYear}
            onChangeText={setExpiryYear}
            maxLength={2}
          />
        </View>
      </View>

      <View style={styles.section}>
        <Text style={styles.label}>CVV</Text>
        <TextInput
          style={styles.input}
          placeholder="123"
          keyboardType="number-pad"
          value={cvv}
          onChangeText={setCvv}
          maxLength={4}
          secureTextEntry
        />
      </View>

      <View style={styles.section}>
        <Text style={styles.label}>Cardholder Name</Text>
        <TextInput
          style={styles.input}
          placeholder="John Doe"
          value={cardholderName}
          onChangeText={setCardholderName}
        />
      </View>

      <TouchableOpacity
        style={styles.button}
        onPress={handleCardPayment}
        disabled={loading}
      >
        {loading ? (
          <ActivityIndicator color="#fff" />
        ) : (
          <Text style={styles.buttonText}>Pay with Card</Text>
        )}
      </TouchableOpacity>

      <TouchableOpacity
        style={[styles.button, styles.applePayButton]}
        onPress={handleApplePay}
        disabled={loading}
      >
        <Text style={styles.buttonText}>Apple Pay</Text>
      </TouchableOpacity>

      <TouchableOpacity
        style={[styles.button, styles.googlePayButton]}
        onPress={handleGooglePay}
        disabled={loading}
      >
        <Text style={styles.buttonText}>Google Pay</Text>
      </TouchableOpacity>

      {transactions.length > 0 && (
        <View style={styles.section}>
          <Text style={styles.subtitle}>Recent Transactions</Text>
          {transactions.slice(0, 5).map((transaction) => (
            <View key={transaction.id} style={styles.transaction}>
              <Text style={styles.transactionText}>
                {transaction.method} - ${transaction.amount}
              </Text>
              <Text style={styles.transactionDate}>
                {new Date(transaction.timestamp).toLocaleDateString()}
              </Text>
            </View>
          ))}
        </View>
      )}
    </ScrollView>
  );
};

